-- 2026年1-4月信用卡行业资讯数据同步
-- 执行方式: 在Railway控制台或本地sqlite3中运行

-- 行业资讯 (industry)
INSERT OR IGNORE INTO articles (title, summary, content, source, url, category, tags, publish_date, crawl_date) VALUES
('多家银行密集停发信用卡，前4月已停发超42款产品', '2026年开年以来，信用卡市场停发潮持续蔓延。民生银行停发11款、农业银行停发13款、交通银行、广发银行等多家银行宣布停发超过42款信用卡产品，其中绝大多数是联名卡和主题卡。', '2026年开年以来，农业银行、民生银行、交通银行、广发银行等多家银行密集发布公告，宣布停止发行多款信用卡产品。据记者不完全统计，年内已有超过42款信用卡产品进入停发名单，其中联名信用卡和主题信用卡成为了清理的重灾区。这种密集动作释放出一个明确信号：银行正加速调整原有的发卡策略。', '21世纪经济报道', 'https://www.21jingji.com/article/20260415/herald/073dc3878a179cb2d39499d7ceb5457b.html', 'industry', '["行业","停发潮","联名卡"]', '2026-04-15', datetime('now')),

('全国信用卡发卡量跌破7亿张，创近7年新低', '央行数据显示，截至2025年末，全国信用卡和借贷合一卡数量为6.96亿张，较2024年末减少约3100万张。信用卡发卡量已连续三年下滑，规模逼近2018年末水平。', '央行发布的《2025年支付体系运行总体情况》显示，截至2025年末，全国信用卡和借贷合一卡的数量为6.96亿张，较2024年末减少约3100万张，较当年三季度末减少。信用卡发卡量连续三年下滑，2025年末正式跌破7亿张关口，创下近七年新低。', '证券时报', 'https://www.stcn.com/article/detail/3757804.html', 'industry', '["行业","发卡量","趋势"]', '2026-04-16', datetime('now')),

('2025年66家信用卡分中心关停，渠道加速收缩', '银行渠道端加速收缩，2025年已有66家信用卡分中心关停，多家银行相继关停独立信用卡App，将功能迁移至手机银行。从国有大行到中小银行，信用卡业务正在经历深刻调整。', '2025年以来，全国已有超过60家信用卡分中心陆续关停。其中交通银行关停数量最多，达58家，覆盖一线城市及部分三、四线城市；民生银行关停5家，广发银行终止3家分中心营业。进入2026年，广州银行等城商行也相继加入关停行列。线上渠道方面，邮储银行关停信用卡独立App并将功能并入手机银行，中国银行也关停了缤纷生活App。', '每日经济新闻', 'https://www.nbd.com.cn/articles/2026-04-19/4346106.html', 'industry', '["行业","渠道","分中心"]', '2026-04-19', datetime('now'));

-- 商机信息 (opportunity)
INSERT OR IGNORE INTO articles (title, summary, content, source, url, category, tags, publish_date, crawl_date) VALUES
('场景金融：信用卡业务从''发卡''转向''场景获客''', '随着信用卡新规实施，银行信用卡业务正从传统的跑马圈地转向场景化、精细化运营。场景金融成为信用卡获客和活客的核心抓手。', '场景金融商机分析：1. 线下场景：商超满减、餐饮优惠、加油返现等；2. 线上场景：电商平台分期、直播带货支付、数字钱包绑定；3. 文旅场景：景区门票优惠、酒店预订折扣、航空里程兑换；4. 出行场景：公交地铁支付、网约车优惠、停车缴费；5. 县域下沉：三四线城市及农村市场信用卡渗透率提升空间巨大。', '行业研究', 'https://credit-news-platform-production-6acb.up.railway.app/', 'opportunity', '["商机","场景金融","获客"]', '2026-04-01', datetime('now')),

('数字化创新：AI+大数据赋能信用卡风控与营销', '信用卡行业数字化转型加速，AI大模型、大数据风控、智能营销成为竞争焦点。银行加大对信用卡数字化渠道的投入。', '数字化创新方向：1. 智能风控：AI驱动的实时交易监测、反欺诈识别；2. 精准营销：基于用户画像的个性化权益推荐；3. 智能客服：大模型驱动的信用卡客服机器人；4. 数字化渠道：信用卡App功能整合、小程序获客；5. 数据治理：EAST数据报送、客户尽职调查系统升级。', '行业研究', 'https://credit-news-platform-production-6acb.up.railway.app/', 'opportunity', '["商机","数字化","AI","风控"]', '2026-04-01', datetime('now')),

('不良资产处置：信用卡不良资产批量转让市场升温', '随着信用卡不良率攀升，银行加速通过批量转让方式出清信用卡不良资产。2026年1月，个人不良贷款批量转让市场持续升温。', '不良资产处置商机：1. 市场规模：2026年1月持牌消费金融公司挂牌转让个人消费贷不良资产包超110亿元；2. 转让方式：单户对公+个人不良贷款批量转让试点；3. 参与机构：资产管理公司（AMC）、地方资产管理公司；4. 估值服务：信用卡不良资产估值、尽职调查服务；5. 清收服务：合规催收、司法诉讼、资产处置。', '银登中心', 'https://www.nfra.gov.cn/', 'opportunity', '["商机","不良资产","批量转让"]', '2026-04-01', datetime('now'));

-- 更新处罚数据 (risk/penalty) - 补充2026年最新处罚
INSERT OR IGNORE INTO articles (title, summary, content, source, url, category, tags, publish_date, crawl_date) VALUES
('建设银行信用卡中心被罚575.27万元', '2026年3月23日，建设银行信用卡中心因客户资信水平调查严重违反审慎经营规则、授信额度管理严重违反审慎经营规则、信用卡分期资金管理严重违反审慎经营规则等14项违规，被上海金融监管局罚没合计575.27万元。', '处罚详情：受罚机构：建设银行信用卡中心；处罚机关：上海金融监管局；处罚日期：2026年3月23日；罚没金额：575.265231万元。违规事由（14项）：1. 客户资信水平调查严重违反审慎经营规则；2. 授信额度管理严重违反审慎经营规则；3. 信用卡分期资金管理严重违反审慎经营规则；4. 其他11项信用卡业务管理违规。', '上海金融监管局', 'https://www.nfra.gov.cn/', 'risk', '["处罚","信用卡中心","审慎经营"]', '2026-03-23', datetime('now')),

('徽商银行南京分行被罚120万元：信用卡汽车分期业务管理不审慎', '2026年3月13日，徽商银行股份有限公司南京分行因信用卡汽车分期业务管理不审慎、服务收费质价不符、贷后管理问题整改不到位，被江苏金融监管局罚款120万元。', '处罚详情：受罚机构：徽商银行股份有限公司南京分行；处罚机关：江苏金融监管局；处罚日期：2026年3月13日；处罚文号：苏金罚决字〔2026〕23号；罚款金额：120万元。违规事由：1. 信用卡汽车分期业务管理不审慎；2. 服务收费质价不符；3. 贷后管理问题整改不到位。责任人处罚：苗睿（时任零售银行部总经理）：警告并罚款8万元；许逸（时任投行与托管业务部总经理助理）：警告并罚款6万元。', '江苏金融监管局', 'https://www.nfra.gov.cn/cn/view/pages/ItemDetail.html?docId=1252207', 'risk', '["处罚","信用卡分期","汽车分期"]', '2026-03-13', datetime('now'));

-- 更新监管政策 (policy) - 补充2026年最新政策
INSERT OR IGNORE INTO articles (title, summary, content, source, url, category, tags, publish_date, crawl_date) VALUES
('三部门：个人消费贷款贴息政策延至2026年底，信用卡账单分期纳入支持范围', '财政部、中国人民银行、金融监管总局联合发布通知，将个人消费贷款财政贴息政策实施期限延长至2026年12月31日，首次将信用卡账单分期业务纳入贴息支持范围，年贴息比例为1个百分点。', '2026年1月20日，财政部、中国人民银行、金融监管总局联合发布《关于优化实施个人消费贷款财政贴息政策有关事项的通知》（财金〔2026〕1号）。主要内容包括：1. 政策期限延长：实施期调整为2025年9月1日至2026年12月31日；2. 信用卡分期纳入：信用卡账单分期业务首次享受财政贴息，年贴息比例1%；3. 贴息标准优化：取消单笔消费贴息500元上限和单家机构1000元上限；4. 经办机构扩容：新增监管评级3A及以上的城商行、农商行、外资银行、消费金融公司、汽车金融公司共500多家。', '财政部/央行/金融监管总局', 'https://www.nfra.gov.cn/cn/view/pages/governmentDetail.html?docId=1243763', 'policy', '["政策","消费贷款","信用卡分期","贴息"]', '2026-01-20', datetime('now'));

